import React from "react";
import { BrowserRouter as Router, Routes, Route, useNavigate } from "react-router-dom";
import "./App.css";

// Components
import Pathology from "./components/Pathology";
import BloodBank from "./components/BloodBank";
import Consultancy from "./components/Consultancy";
import Medicine from "./components/Medicine";

function Home() {
  return (
    <div>
      {/* Hero */}
      <section className="hero">
        <h2>Your Health, Our Priority</h2>
        <p>Connecting people to better healthcare solutions.</p>
        <button
          className="get-started-btn"
          onClick={() =>
            document.querySelector(".sections").scrollIntoView({ behavior: "smooth" })
          }
        >
          Get Started
        </button>
      </section>

      {/* Sections */}
      <section className="sections">
        <Pathology />
        <BloodBank />
        <Consultancy />
        <Medicine />
      </section>

      {/* Login & Register */}
      <div className="auth-forms">
        <div className="login-form">
          <h3>Login</h3>
          <form>
            <input type="email" placeholder="Email" />
            <input type="password" placeholder="Password" />
            <button type="submit">Login</button>
          </form>
        </div>

        <div className="register-form">
          <h3>Register</h3>
          <form>
            <input type="text" placeholder="Full Name" />
            <input type="email" placeholder="Email" />
            <input type="password" placeholder="Password" />
            <button type="submit">Register</button>
          </form>
        </div>
      </div>
    </div>
  );
}

function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/pathology" element={<Pathology fullPage />} />
        <Route path="/blood-bank" element={<BloodBank fullPage />} />
        <Route path="/consultancy" element={<Consultancy fullPage />} />
        <Route path="/medicine" element={<Medicine fullPage />} />
      </Routes>
    </Router>
  );
}

export default App;
